#include <stdio.h>
#include <string.h>
#include <stdlib.h>

/*
 * Simple XOR-based encryption demonstration for educational purposes
 * In real systems, use AES or other strong encryption algorithms
 */

#define MAX_BUFFER 256

// XOR encryption/decryption (same operation for both)
void xor_encrypt_decrypt(char *data, const char *key, size_t data_len) {
 size_t key_len = strlen(key);

 for (size_t i = 0; i < data_len; i++) {
 data[i] = data[i] ^ key[i % key_len];
 }
}

// Simple hash function (similar to a basic checksum)
unsigned int simple_hash(const char *data) {
 unsigned int hash = 5381;
 int c;

 while ((c = *data++)) {
 hash = ((hash << 5) + hash) + c; // hash * 33 + c
 }

 return hash;
}

// Generate HMAC-like signature
void generate_hmac(const char *message, const char *key, char *output) {
 char combined[MAX_BUFFER];

 // Combine message and key
 snprintf(combined, MAX_BUFFER, "%s%s", message, key);

 // Hash the combined string twice for better security
 unsigned int hash1 = simple_hash(combined);
 unsigned int hash2 = simple_hash((const char *)&hash1);

 // Convert to hex string
 snprintf(output, MAX_BUFFER, "%08x%08x", hash1, hash2);
}

// Verify HMAC signature
int verify_hmac(const char *message, const char *key, const char *signature) {
 char computed_sig[MAX_BUFFER];

 generate_hmac(message, key, computed_sig);

 // Use constant-time comparison to prevent timing attacks
 int result = 0;
 for (int i = 0; signature[i] && computed_sig[i]; i++) {
 result |= signature[i] ^ computed_sig[i];
 }

 return (result == 0);
}

// Simulate Kerberos-style ticket granting
typedef struct {
 char username[50];
 unsigned int timestamp;
 unsigned int session_key_hash;
} Ticket;

void create_ticket(Ticket *ticket, const char *username, unsigned int session_key) {
 strncpy(ticket->username, username, sizeof(ticket->username) - 1);
 ticket->timestamp = (unsigned int)time(NULL);
 ticket->session_key_hash = simple_hash((const char *)&session_key);
}

void print_ticket(const Ticket *ticket) {
 printf("Ticket Information:\n");
 printf(" Username: %s\n", ticket->username);
 printf(" Timestamp: %u\n", ticket->timestamp);
 printf(" Session Key Hash: %08x\n", ticket->session_key_hash);
}

