import java.security.*;
import java.util.Base64;
import java.nio.charset.StandardCharsets;
import java.util.Scanner;

/**
 * Asymmetric Authentication Demo using RSA
 * Demonstrates public/private key encryption for secure authentication
 */
public class RSAAuthenticationDemo {

 private KeyPair keyPair;
 private String username;

 public RSAAuthenticationDemo(String username) throws NoSuchAlgorithmException {
 this.username = username;
 // Generate RSA key pair (2048-bit for security)
 KeyPairGenerator generator = KeyPairGenerator.getInstance("RSA");
 generator.initialize(2048);
 this.keyPair = generator.generateKeyPair();
 }

 // Sign a message with private key (creates digital signature)
 public String signMessage(String message) throws Exception {
 Signature signer = Signature.getInstance("SHA256withRSA");
 signer.initSign(keyPair.getPrivate());
 signer.update(message.getBytes(StandardCharsets.UTF_8));

 byte[] signature = signer.sign();
 return Base64.getEncoder().encodeToString(signature);
 }

 // Verify signature with public key
 public boolean verifySignature(String message, String signatureStr) throws Exception {
 Signature verifier = Signature.getInstance("SHA256withRSA");
 verifier.initVerify(keyPair.getPublic());
 verifier.update(message.getBytes(StandardCharsets.UTF_8));

 byte[] signature = Base64.getDecoder().decode(signatureStr);
 return verifier.verify(signature);
 }

 // Encrypt data with public key (for key exchange or secure transmission)
 public String encryptWithPublicKey(String plaintext) throws Exception {
 Cipher cipher = Cipher.getInstance("RSA");
 cipher.init(Cipher.ENCRYPT_MODE, keyPair.getPublic());

 byte[] encrypted = cipher.doFinal(plaintext.getBytes(StandardCharsets.UTF_8));
 return Base64.getEncoder().encodeToString(encrypted);
 }

 // Decrypt data with private key
 public String decryptWithPrivateKey(String ciphertext) throws Exception {
 Cipher cipher = Cipher.getInstance("RSA");
 cipher.init(Cipher.DECRYPT_MODE, keyPair.getPrivate());

 byte[] decrypted = cipher.doFinal(Base64.getDecoder().decode(ciphertext));
 return new String(decrypted, StandardCharsets.UTF_8);
 }

 // Get public key string (for sharing with others)
 public String getPublicKeyString() {
 return Base64.getEncoder().encodeToString(keyPair.getPublic().getEncoded());
 }

 // Simulate authentication process
 public static void authenticateUser() throws Exception {
 System.out.println("=== RSA Authentication Demo ===\n");

 // Create two parties: Client and Server
 RSAAuthenticationDemo client = new RSAAuthenticationDemo("client_user");
 RSAAuthenticationDemo server = new RSAAuthenticationDemo("server");

 System.out.println("Step 1: Client generates key pair");
 System.out.println("Step 2: Client sends public key to server\n");

 // Step 1: Client sends authentication request with public key
 String clientPublicKey = client.getPublicKeyString();
 System.out.println("Client's Public Key (first 50 chars): " + 
 clientPublicKey.substring(0, Math.min(50, clientPublicKey.length())) + "...");

 // Step 2: Server encrypts a challenge with client's public key
 String challenge = "AUTH_CHALLENGE_" + System.currentTimeMillis();
 System.out.println("\nStep 3: Server creates challenge: " + challenge);

 String encryptedChallenge = server.encryptWithPublicKey(challenge);
 System.out.println("Step 4: Server encrypts challenge with client's public key");
 System.out.println("Encrypted: " + encryptedChallenge.substring(0, 50) + "...");

 // Step 3: Client decrypts the challenge with private key
 String decryptedChallenge = client.decryptWithPrivateKey(encryptedChallenge);
 System.out.println("\nStep 5: Client decrypts challenge with private key: " + decryptedChallenge);

 // Step 4: Client signs the decrypted challenge
 String clientSignature = client.signMessage(decryptedChallenge);
 System.out.println("Step 6: Client signs the challenge (digital signature)");
 System.out.println("Signature: " + clientSignature.substring(0, 50) + "...");

 // Step 5: Server verifies the signature
 boolean isValid = client.verifySignature(decryptedChallenge, clientSignature);
 System.out.println("\nStep 7: Server verifies signature with client's public key");
 System.out.println("Authentication Result: " + (isValid ? "SUCCESS ✓" : "FAILED ✗"));

 // Demonstrate mutual authentication
 System.out.println("\n--- Mutual Authentication ---\n");

 // Server sends its own signed message
 String serverMessage = "SERVER_AUTHENTICATED";
 String serverSignature = server.signMessage(serverMessage);
 System.out.println("Server sends signed message: " + serverMessage);

 boolean serverVerified = server.verifySignature(serverMessage, serverSignature);
 System.out.println("Client verifies server: " + (serverVerified ? "SUCCESS ✓" : "FAILED ✗"));

 System.out.println("\n=== Mutual Authentication Complete ===");
 }

 public static void main(String[] args) {
 try {
 authenticateUser();
 } catch (Exception e) {
 System.err.println("Error: " + e.getMessage());
 e.printStackTrace();
 }
 }
}
